package codegen

import (
	"flag"
	"os"
	"path/filepath"
	"strings"
	"testing"
)

// updateGolden controls whether [expectGolden] rewrites the on-disk
// reference file with `actual` instead of comparing. Toggle from the
// CLI to refresh references after an INTENTIONAL codegen change:
//
//	go test ./internal/codegen -run TestEmitEnum -update
//
// Always inspect the resulting `git diff` before committing.
var updateGolden = flag.Bool("update", false, "rewrite golden snapshot files instead of comparing")

// expectGolden compares `actual` (generated bytes) against the
// reference file at `testdata/golden/<name>`. When the file does not
// exist OR the `-update` flag is set, it writes `actual` and passes.
// Otherwise it diffs the two strings and fails the test on mismatch
// with a side-by-side preview pointing the eye at the diverging
// lines.
//
// Use sparingly: golden tests are easy to over-pin. Reach for them
// when the assertion would otherwise be a long chain of
// `strings.Contains` checks against generated source - the diff
// output beats every individual check, and `-update` makes
// intentional refactors a 1-command refresh.
func expectGolden(t *testing.T, name, actual string) {
	t.Helper()
	path := filepath.Join("testdata", "golden", name)
	if *updateGolden {
		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
			t.Fatalf("mkdir testdata/golden: %v", err)
		}
		if err := os.WriteFile(path, []byte(actual), 0o644); err != nil {
			t.Fatalf("write golden %s: %v", path, err)
		}
		t.Logf("wrote golden %s (%d bytes)", path, len(actual))
		return
	}
	want, err := os.ReadFile(path)
	if err != nil {
		if os.IsNotExist(err) {
			t.Fatalf("golden file %s does not exist; run with -update to create it", path)
		}
		t.Fatalf("read golden %s: %v", path, err)
	}
	// Compare with CRLF normalised: a Windows checkout may give the golden
	// file CRLF line endings while the generated output is always LF.
	wantStr := strings.ReplaceAll(string(want), "\r\n", "\n")
	if wantStr == actual {
		return
	}
	t.Errorf("golden mismatch (%s) - diff first divergence:\n%s", path, firstDiff(wantStr, actual))
}

// firstDiff returns a short side-by-side preview of where want and
// got first diverge. Avoids dumping multi-kilobyte mismatches into
// CI logs while still pointing the reader at the offending line.
func firstDiff(want, got string) string {
	wantLines := strings.SplitSeq(want, "\n")
	gotLines := strings.SplitSeq(got, "\n")
	wIter, gIter := wantLines, gotLines
	wantSlice := stringsCollect(wIter)
	gotSlice := stringsCollect(gIter)
	max := len(wantSlice)
	if len(gotSlice) > max {
		max = len(gotSlice)
	}
	for i := 0; i < max; i++ {
		w, g := "", ""
		if i < len(wantSlice) {
			w = wantSlice[i]
		}
		if i < len(gotSlice) {
			g = gotSlice[i]
		}
		if w != g {
			start := i - 2
			if start < 0 {
				start = 0
			}
			end := i + 4
			if end > max {
				end = max
			}
			var sb strings.Builder
			for j := start; j < end; j++ {
				marker := "  "
				if j == i {
					marker = "→ "
				}
				wj, gj := "", ""
				if j < len(wantSlice) {
					wj = wantSlice[j]
				}
				if j < len(gotSlice) {
					gj = gotSlice[j]
				}
				sb.WriteString(marker)
				sb.WriteString("want: ")
				sb.WriteString(wj)
				sb.WriteString("\n")
				sb.WriteString(marker)
				sb.WriteString("got:  ")
				sb.WriteString(gj)
				sb.WriteString("\n")
			}
			return sb.String()
		}
	}
	return "(strings differ in length but match line-by-line up to the shorter end)"
}

// stringsCollect drains a [strings.SplitSeq] iterator into a slice so
// random-access indexing in [firstDiff] stays simple. The size of
// the source string in test scenarios is small enough that the
// double-allocation is irrelevant.
func stringsCollect(it func(yield func(string) bool)) []string {
	var out []string
	it(func(s string) bool {
		out = append(out, s)
		return true
	})
	return out
}
